const normalizeExternalId = (value) => String(value || '').replace(/[^a-zA-Z0-9_-]+/g, '_').slice(0, 180);

return items
  .map((item) => {
    const source = item.json || {};
    const title = source.title || '';
    const link = source.link || source.guid || '';
    const publishedAt = source.isoDate || source.pubDate || source.pubdate || new Date().toISOString();
    const summaryRaw = source.contentSnippet || source.content || source['content:encoded'] || source.summary || '';
    const externalId = normalizeExternalId(link || `${publishedAt}|${title}`);

    return {
      json: {
        source: 'moex_rss_all',
        title,
        link,
        published_at: publishedAt,
        summary_raw: summaryRaw,
        external_id: externalId,
        payload_json: JSON.stringify(source),
      },
    };
  })
  .filter((item) => item.json.external_id);

const computeHash = (value) => {
  const input = String(value || '');
  let hash = 0;
  for (let index = 0; index < input.length; index++) {
    hash = ((hash << 5) - hash) + input.charCodeAt(index);
    hash |= 0;
  }
  return `h${(hash >>> 0).toString(16)}`;
};

const newsItems = items.filter((item) => item.json.external_id && item.json.search_text);
const watchlist = items.filter((item) => item.json.secid);

if (newsItems.length === 0 || watchlist.length === 0) {
  return [];
}

const results = [];

for (const news of newsItems) {
  const haystack = news.json.search_text || '';

  for (const item of watchlist) {
    const row = item.json;
    const keywords = [
      row.secid,
      row.issuer_name,
      ...(String(row.news_keywords || '')
        .split(',')
        .map((value) => value.trim())
        .filter(Boolean)),
    ]
      .map((value) => String(value || '').toLowerCase())
      .filter(Boolean);

    const matched = [...new Set(keywords.filter((keyword) => haystack.includes(keyword)))];
    if (matched.length === 0) continue;

    const knowledgeText = [
      'Источник: Moscow Exchange RSS',
      `Инструмент: ${row.secid}`,
      `Эмитент: ${row.issuer_name || row.secid}`,
      `Группа: ${row.instrument_group || 'stocks'}`,
      `Дата публикации: ${news.json.published_at}`,
      `Заголовок: ${news.json.title}`,
      `Ссылка: ${news.json.link || 'n/a'}`,
      `Ключевые совпадения: ${matched.join(', ')}`,
      `Текст новости: ${news.json.summary_raw || 'n/a'}`,
    ].join('\n');

    const sourceKey = `moex/news/${row.secid}/${news.json.external_id}`;
    const payloadObject = {
      source: news.json.source,
      secid: row.secid,
      issuer_name: row.issuer_name,
      instrument_group: row.instrument_group,
      external_id: news.json.external_id,
      published_at: news.json.published_at,
      title: news.json.title,
      link: news.json.link,
      matched_keywords: matched,
      summary_raw: news.json.summary_raw,
    };
    const payloadJson = JSON.stringify(payloadObject);
    const documentHash = computeHash(knowledgeText);

    results.push({
      json: {
        source: news.json.source,
        secid: row.secid,
        engine: row.engine,
        market: row.market,
        board: row.board,
        issuer_name: row.issuer_name,
        instrument_group: row.instrument_group,
        external_id: news.json.external_id,
        published_at: news.json.published_at,
        title: news.json.title,
        link: news.json.link,
        summary_raw: news.json.summary_raw,
        matched_keywords: matched.join(', '),
        summary_text: knowledgeText,
        knowledge_text: knowledgeText,
        source_key: sourceKey,
        document_hash: documentHash,
        payload_json: payloadJson,
      },
    });
  }
}

return results;

return items
  .filter((item) => item.json.inserted === true || item.json.inserted === 'true')
  .map((item) => {
    const title = item.json.title || '';
    const summaryRaw = item.json.summary_raw || item.json.content_raw || '';
    const link = item.json.link || '';
    return {
      json: {
        ...item.json,
        summary_raw: summaryRaw,
        search_text: `${title}\n${summaryRaw}\n${link}`.toLowerCase(),
      },
    };
  });
